interface Comment { id: string; text: string; replies: Comment[]; }
function CommentTree({ comment, depth = 0 }: { comment: Comment; depth?: number }) {
  return (
    <div style={{ paddingLeft: depth * 16 }}>
      <p>{comment.text}</p>
      {comment.replies.map(r => <CommentTree key={r.id} comment={r} depth={depth + 1} />)}
    </div>
  );
}

interface FsNode { name: string; type: 'file'|'folder'; children?: FsNode[]; }
function findFiles(node: FsNode, ext: string, path = ''): string[] {
  const fullPath = path + '/' + node.name;
  if (node.type === 'file') return fullPath.endsWith(ext) ? [fullPath] : [];
  return (node.children ?? []).flatMap(child => findFiles(child, ext, fullPath));
}

function findActivePath(items: NavItem[], target: string, path: NavItem[] = []): NavItem[] | null {
  for (const item of items) {
    const current = [...path, item];
    if (item.href === target) return current;
    if (item.children) {
      const found = findActivePath(item.children, target, current);
      if (found) return found;
    }
  }
  return null;
}

