interface TreeNode<T> {
  value: T;
  children: TreeNode<T>[];
}

// DFS pre-order (recursive) — visit node before children
function dfsPreOrder<T>(node: TreeNode<T>, visit: (val: T) => void): void {
  visit(node.value);
  for (const child of node.children) {
    dfsPreOrder(child, visit);
  }
}

// DFS post-order — visit node after all children
function dfsPostOrder<T>(node: TreeNode<T>, visit: (val: T) => void): void {
  for (const child of node.children) {
    dfsPostOrder(child, visit);
  }
  visit(node.value);
}

// BFS level-order using queue
function bfs<T>(root: TreeNode<T>, visit: (val: T, level: number) => void): void {
  const queue: Array<{ node: TreeNode<T>; level: number }> = [{ node: root, level: 0 }];
  while (queue.length > 0) {
    const { node, level } = queue.shift()!;
    visit(node.value, level);
    for (const child of node.children) {
      queue.push({ node: child, level: level + 1 });
    }
  }
}

// Flatten tree to array (DFS pre-order)
function flatten<T>(node: TreeNode<T>): T[] {
  return [node.value, ...node.children.flatMap(flatten)];
}

// Find path to node matching predicate
function findPath<T>(node: TreeNode<T>, pred: (val: T) => boolean, path: T[] = []): T[] | null {
  const current = [...path, node.value];
  if (pred(node.value)) return current;
  for (const child of node.children) {
    const found = findPath(child, pred, current);
    if (found) return found;
  }
  return null;
}

