interface NavItem { label: string; children?: NavItem[]; }
function maxDepth(item: NavItem): number {
  if (!item.children || item.children.length === 0) return 1;
  return 1 + Math.max(...item.children.map(maxDepth));
}

interface Category { id: string; name: string; children?: Category[]; }
function flattenCategories(cats: Category[], prefix = ''): Array<{id:string; label:string}> {
  return cats.flatMap(cat => {
    const label = prefix ? `${prefix} > ${cat.name}` : cat.name;
    const self = { id: cat.id, label };
    const children = cat.children ? flattenCategories(cat.children, label) : [];
    return [self, ...children];
  });
}

interface NavItem { label: string; href?: string; children?: NavItem[]; }
function getBreadcrumb(items: NavItem[], slug: string, path: NavItem[] = []): NavItem[] | null {
  for (const item of items) {
    const current = [...path, item];
    if (item.href === slug) return current;
    if (item.children) {
      const result = getBreadcrumb(item.children, slug, current);
      if (result) return result;
    }
  }
  return null;
}
